import { Timer } from "./timer.ts";
import config from "../config/default.json";

const [, , command, arg] = process.argv;
const timer = new Timer({ tickMs: config.tickMs });

switch (command) {
  case "start":
    timer.start(arg ?? config.defaultLabel);
    break;
  case "count":
    timer.countdown(arg ?? config.defaultCountdown);
    break;
  default:
    console.log("usage: tempo <start|count> [arg]");
}
```

