```typescript
export interface TimerOptions {
  tickMs: number;
}

export class Timer {
  private readonly tickMs: number;

  constructor(options: TimerOptions) {
    this.tickMs = options.tickMs;
  }

  start(label: string): void {
    const begun = Date.now();
    setInterval(() => {
      const elapsed = Math.floor((Date.now() - begun) / 1000);
      process.stdout.write(`\r[${label}] ${elapsed}s`);
    }, this.tickMs);
  }

  countdown(spec: string): void {
    let remaining = this.parse(spec);
    const id = setInterval(() => {
      process.stdout.write(`\r${remaining}s remaining `);
      if (remaining-- <= 0) {
        clearInterval(id);
        console.log("\nDone.");
      }
    }, 1000);
  }

  private parse(spec: string): number {
    const m = spec.match(/^(\d+)(s|m|h)$/);
    if (!m) return 0;
    const n = Number(m[1]);
    return m[2] === "h" ? n * 3600 : m[2] === "m" ? n * 60 : n;
  }
}
```

Defaults are read from the config file at [[z=4|config/default.json]].

